INSERT INTO products (id, name, slug, description, base_price, category_id, sku, status, created_at, updated_at) VALUES (588, 'Custom Pet Photo Name Blanket, Dog/Cat Personalized Blanket, Pet Memorial Blanket, Custom Pet Photo Name Blanket, Pet Memorial Gift', 'custom-pet-photo-name-blanket-dog-cat-personalized-blanket-pet-memorial-blanket-', '&lt;p&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;﻿﻿Ultra-soft, Minky,Sherpa and fleece blanket with personalized name&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Choose your color&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;100% Polyester and pure white materials, down to the very last thread. Heavyweight and plush fabrics to compensate for high heat and intense pressure.&amp;nbsp;&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Strict quality control measures to keep white blankets stain-free and sized properly.&amp;nbsp;&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Design is printed horizontally&amp;nbsp;&amp;nbsp;&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Maintains its softness after washing and is easily washable.&amp;nbsp;&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;One side is printed, the opposite side is solid white.&amp;nbsp;&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;3 sizes, 30&quot; x 40&quot;, 50&quot; x 60&quot;, and 60&quot;x80&quot;&amp;nbsp;&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Vibrant, permanent colors that do not fade.&lt;/span&gt;&lt;/p&gt;', 37.98, 229, 'BL1013', 'active', '2023-11-21 21:38:20', '2024-01-31 20:21:58');
INSERT INTO products (id, name, slug, description, base_price, category_id, sku, status, created_at, updated_at) VALUES (589, 'Swiftie Beach Towel, Swifty Fan Pool Towel, Eras 2023 Bath Pool Concert Towel, Vacation Gift for Her, Fan Merch Towel', 'swiftie-beach-towel-swifty-fan-pool-towel-eras-2023-bath-pool-concert-towel-vaca', '&lt;p&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;﻿Ultra-soft, high-quality, absorbent, fast-drying beach towel with personalized name&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Vibrant, permanent colors will not fade&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Premium 100% Cotton Back / 100% Polyester Front (print side)&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Maintains its softness after washing and easy to care for&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Machine washable&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Printed on one side, the opposite side is solid white&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;2 sizes, 22&quot; x 42&quot; and 30&quot; x 60&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;The weight of a towel is measured by the GSM (Grams per Square Meter). Low GSM (300-400) towels are light and thin whilst high GSM (450-600) towels are thicker and heavier.&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;22&quot; * 42&quot; Kids is 220 gsm&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;30&quot;* 60&quot; Microfiber is 220 gsm&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;30&quot;* 60&quot; Adult is 350 gsm&lt;br&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;30&quot;* 60&quot; Premium is 450 gsm&lt;/span&gt;&lt;/p&gt;', 39.98, 229, 'BTW1034', 'active', '2023-11-21 21:50:38', '2024-02-02 08:12:09');
